/**
 * Delete the entire database (use with caution)
 */
export async function deleteDatabase(): Promise<void> {
  // Close the cached connection so deletion isn't blocked
  if (dbPromise) {
    try {
      const db = await dbPromise;
      db.close();
    } catch {
      // Connection may already be closed
    }
    dbPromise = null;
    legacyMigrationDone = false;
  }

  return new Promise((resolve, reject) => {
    const names = [DB_NAME, LEGACY_DB_NAME];
    let remaining = names.length;
    let settled = false;

    const finish = () => {
      remaining -= 1;
      if (!settled && remaining === 0) {
        settled = true;
        resolve();
      }
    };

    for (const name of names) {
      const request = indexedDB.deleteDatabase(name);

      request.onsuccess = () => {
        finish();
      };

      request.onerror = () => {
        if (settled) return;
        settled = true;
        reject(new Error(`Failed to delete database: ${request.error?.message}`));
      };

      request.onblocked = () => {
        if (settled) return;
        settled = true;
        reject(new Error(`Database deletion blocked for ${name} - close all tabs using this database`));
      };
    }
  });
}

